module RefModule (
    input clk,
    input rst,
    input signal_in,
    output reg zero_crossed
);

    reg obf_signal_prev;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            zero_crossed <= 0;
            obf_signal_prev <= 0;
        end else begin
            zero_crossed <= (signal_in && !obf_signal_prev) || (!signal_in && obf_signal_prev);
            obf_signal_prev <= signal_in;
        end
    end
endmodule
